// components/fields/Container.tsx

import React from 'react';
import {type FieldValues, useFormContext} from 'react-hook-form';
import type {IContainer, UseFieldLogicElementProps} from '@lmb-it/kitsconcerto-types';
import {Label, Text} from "../../../../_compat";

// The Container needs the parentPath to know which part of the form values to watch.
interface ContainerProps<T extends FieldValues> extends UseFieldLogicElementProps<T> {
    parentPath?: string;
}

export const Container = <T extends FieldValues>({
                                                     element,
                                                     control, groupField,
                                                     getValues,
                                                     parentPath = '', fieldLogic
                                                 }: ContainerProps<T>) => {
    // 1. Get the full formContext from the provider.
    // This is the one case where a component needs more than what useFieldLogic provides.
    const formContext = useFormContext<T>();

    const {
        field, label, helperText, watchedValues
    } = fieldLogic;

    // 2. Watch the parent path to get currentGroupValues.
    // We watch the path without the trailing dot (e.g., 'user' or 'addresses.0').
    // const currentGroupValues = useWatch({
    //     control,
    //     name: parentPath.endsWith('.') ? parentPath.slice(0, -1) as any : parentPath as any,
    // });

    const containerElement = element as IContainer<T>;

    // 4. Call the children render prop with the required data.
    return (
        <>

            {label && (
                <Label as="h2" label={label} elementId={element.id as string}/>
            )}
            {helperText && typeof helperText != "function" && (
                <Text fontSize={10} as={"small"}>
                    {helperText}
                </Text>
            )}
            {typeof containerElement.children !== 'function'?containerElement.children:containerElement.children(field, formContext, groupField, watchedValues)}
        </>
    );
};

export default Container;
